import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { QuickGuideParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/roleplay/QuickGuideParser';

export class QuickGuideEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, QuickGuideParser);
    }

    public getParser(): QuickGuideParser {
        return this.parser as QuickGuideParser;
    }
}
